import { useEffect, useState, type FocusEvent } from 'react';
import { CircleHelp } from 'lucide-react';
import { DisabledReasonTooltip } from '@/components/ui/disabled-reason-tooltip';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import HelpIcon from '@/components/help/HelpIcon';
import NodeSelectionPanel from '@/features/analysis/common/components/NodeSelectionPanel';
import { ANALYSIS_LOCKED_MESSAGE } from '@/features/analysis/common/components/AnalysisLockedNotice';
import type { NodeColumnSelection } from '@/hooks/useAutoNodeColumns';
import type { ColumnInfo } from '@/utils/columnTypes';
import type { NodeLike } from '@/hooks/useNodeColumnInfos';
import { AnalysisCardLayout } from '@/features/analysis/common/components/AnalysisCardLayout';
import type { SnapshotToolKey } from '@/features/snapshot-view';

export type CorpusSample = {
  percent: string;
  enabled: boolean;
};

type Props = {
  selectedNodes: Array<{ id?: string; name?: string }>;
  nodeColumnSelections: NodeColumnSelection[];
  onColumnChange: (nodeId: string, column: string) => void;
  nodeColors: Record<string, string>;
  onNodeColorChange: (nodeId: string, color: string) => void;
  defaultPalette: string[];
  isLocked: boolean;
  getNodeColumns: (node: NodeLike | null | undefined, idx?: number) => ColumnInfo[];
  actionState: { runDisabled: boolean; clearDisabled: boolean; runLabel: string; runDisabledReason?: string };
  corpusSamples: CorpusSample[];
  nodeDocCounts: number[];
  onCorpusSampleChange: (idx: number, update: Partial<CorpusSample>) => void;
  topicSizeMode: 'min' | 'exact';
  onTopicSizeModeChange: (mode: 'min' | 'exact') => void;
  topicSizeValue: number;
  topicSizeUserSet: boolean;
  topicSizeWarning: 'orange' | 'red' | null;
  onTopicSizeValueChange: (value: number) => void;
  showSamplingWarning: boolean;
  randomSeed: number;
  randomSeedUserSet: boolean;
  onRandomSeedChange: (value: number) => void;
  representativeWordsCount: number;
  representativeWordsCountUserSet: boolean;
  /**
   * When locked, the maximum display value the user can pick for "Words per
   * topic" without re-running — the originally-fitted count. `null` means
   * unlocked (no server-side cap).
   */
  representativeWordsCountServerMax?: number | null;
  /** Override for the tooltip on the locked "Words per topic" input.
   * Live mode tells the user how to lift the cap ("Clear Results to
   * fit with a higher count"); snapshot mode passes its own copy
   * because Clear Results doesn't apply there. */
  representativeWordsCountLockedReason?: string;
  onRepresentativeWordsCountChange: (value: number) => void;
  isRunning: boolean;
  isClearing: boolean;
  onRun: () => void | Promise<void>;
  onClear: () => void | Promise<void>;
  hasMissingColumns: boolean;
  resultState?: string;
  /** When true, disables every parameter input on the card (sampling
   * toggles + %, topic-size mode/value, random seed, words-per-topic).
   * Snapshot mode passes ``true`` — the captured run's parameters are
   * displayed read-only, and live Run/Update is gated separately at
   * the feature level. ``isLocked`` controls only the NodeSelectionPanel
   * lock; the parameter inputs stay live-editable on lock by design
   * (the live UI uses them to stage the next Update). */
  inputsDisabled?: boolean;
  /** Displayed when the panel is locked. Defaults to the standard
   * "locked while results loaded" message; snapshot mode passes a
   * tailored "viewing saved snapshot" string. */
  lockedMessage?: string;
  /** Snapshot Save/Load slot. Forwarded straight to the underlying
   * AnalysisCardLayout, which renders <SnapshotActions> alongside any
   * other header actions. Mirrors the per-tool wiring used by the
   * other parameter cards. */
  snapshot?: {
    tool: SnapshotToolKey;
    onSave?: (filename: string, description: string) => Promise<void>;
    saveDisabledReason?: string | null;
    onOpen?: (filename: string) => Promise<void>;
    nodeLabels?: string[];
  };
};

export function TopicModelingParameterPanel({
  selectedNodes,
  nodeColumnSelections,
  onColumnChange,
  nodeColors,
  onNodeColorChange,
  defaultPalette,
  isLocked,
  getNodeColumns,
  actionState,
  corpusSamples,
  nodeDocCounts,
  onCorpusSampleChange,
  topicSizeMode,
  onTopicSizeModeChange,
  topicSizeValue,
  topicSizeUserSet,
  topicSizeWarning,
  onTopicSizeValueChange,
  showSamplingWarning,
  randomSeed,
  randomSeedUserSet,
  onRandomSeedChange,
  representativeWordsCount,
  representativeWordsCountUserSet,
  representativeWordsCountServerMax = null,
  representativeWordsCountLockedReason,
  onRepresentativeWordsCountChange,
  isRunning,
  isClearing,
  onRun,
  onClear,
  hasMissingColumns,
  resultState,
  inputsDisabled = false,
  lockedMessage = ANALYSIS_LOCKED_MESSAGE,
  snapshot,
}: Props) {
  const [topicSizeValueDraft, setTopicSizeValueDraft] = useState(() => String(topicSizeValue));

  useEffect(() => {
    setTopicSizeValueDraft(String(topicSizeValue));
  }, [topicSizeValue]);

  const handleTopicSizeValueBlur = (event: FocusEvent<HTMLInputElement>) => {
    const raw = Number(event.currentTarget.value);
    const next = Math.max(2, isNaN(raw) ? 2 : Math.round(raw));
    setTopicSizeValueDraft(String(next));
    onTopicSizeValueChange(next); // always call — even unchanged — to solidify grey placeholder
  };

  const [representativeWordsCountDraft, setRepresentativeWordsCountDraft] = useState(
    () => String(representativeWordsCount),
  );

  useEffect(() => {
    setRepresentativeWordsCountDraft(String(representativeWordsCount));
  }, [representativeWordsCount]);

  // Backend now fits with at least 50 representative words and serves up to
  // 2× the originally-fitted count, so post-fit we can let the user scale
  // up without rerunning. Pre-fit cap stays at 50 since there's no fitted
  // count to double yet.
  const representativeWordsCountCap = isLocked && representativeWordsCountServerMax
    ? Math.max(50, 2 * representativeWordsCountServerMax)
    : 50;

  const handleRepresentativeWordsCountBlur = (event: FocusEvent<HTMLInputElement>) => {
    const raw = Number(event.currentTarget.value);
    const rounded = Number.isFinite(raw) ? Math.round(raw) : 3;
    const clamped = Math.min(representativeWordsCountCap, Math.max(3, rounded));
    setRepresentativeWordsCountDraft(String(clamped));
    onRepresentativeWordsCountChange(clamped);
  };

  return (
    <AnalysisCardLayout
      title="Topic Modelling - BERTopic"
      info={{
        targetKey: 'topic-modeling.overview',
        label: 'About Topic Modeling',
        tooltip: 'Learn what topic modeling is and how it can help you.',
      }}
      snapshot={snapshot}
      actions={{
        onRun,
        onClear,
        runDisabled: actionState.runDisabled || isRunning || hasMissingColumns,
        runDisabledReason: hasMissingColumns
          ? 'Select a column for each data block'
          : actionState.runDisabledReason,
        clearDisabled: actionState.clearDisabled || isClearing,
        isRunning,
        isClearing,
        hasResult: resultState === 'successful' || resultState === 'failed',
        runLabel: actionState.runLabel,
      }}
    >
      <NodeSelectionPanel
        selectedNodes={selectedNodes}
        nodeColumnSelections={nodeColumnSelections}
        onColumnChange={onColumnChange}
        nodeColors={nodeColors}
        onColorChange={onNodeColorChange}
        defaultPalette={defaultPalette}
        getNodeColumns={getNodeColumns}
        maxCompare={2}
        showShape
        disabled={isLocked}
        locked={isLocked}
        allowedDataTypes={['string']}
        lockedMessage={lockedMessage}
        originalCount={selectedNodes.length}
      />

      <div className="mt-4 grid grid-cols-2 gap-6">

        {/* ── Left column: Data Block Sampling ── */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center gap-1.5">
            <Label className="text-sm font-medium">Data Block Sampling</Label>
            <HelpIcon targetKey="analysis.topic-modeling.sampling" />
          </div>

          {/* Always render exactly 2 rows */}
          {([0, 1] as const).map((idx) => {
            const node = selectedNodes[idx];
            const sample = corpusSamples[idx] ?? { percent: '100', enabled: false };
            const nodeId = node?.id ?? '';
            const color = nodeId
              ? (nodeColors[nodeId] ?? defaultPalette[idx] ?? '#6b7280')
              : '#9ca3af';
            const nDocs = nodeDocCounts[idx] ?? 0;

            // When unchecked: display 100 and show full doc count
            const displayPercent = sample.enabled ? sample.percent : '100';
            const effectiveDocs = sample.enabled
              ? Math.max(
                  1,
                  Math.round(
                    (nDocs * Math.min(100, Math.max(1, Number(sample.percent) || 100))) / 100
                  )
                )
              : nDocs;

            if (!node) {
              // Placeholder row — same height as a real row, no interaction
              return (
                <div
                  key={`placeholder-${idx}`}
                  className="flex items-center gap-2 opacity-25"
                  style={{ minHeight: '2rem' }}
                >
                  <div
                    className="h-5 w-5 flex-shrink-0 rounded-full border-2"
                    style={{ borderColor: '#9ca3af' }}
                  />
                  <span className="text-sm text-muted-foreground">—</span>
                </div>
              );
            }

            return (
              <div key={nodeId || idx} className="flex items-center gap-2">
                {/* Coloured circle radio toggle */}
                <button
                  type="button"
                  onClick={() =>
                    onCorpusSampleChange(idx, { enabled: !sample.enabled })
                  }
                  aria-label={sample.enabled ? 'Disable sampling' : 'Enable sampling'}
                  disabled={inputsDisabled}
                  className="h-5 w-5 flex-shrink-0 rounded-full border-2 transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-60"
                  style={{
                    backgroundColor: sample.enabled ? color : 'transparent',
                    borderColor: color,
                  }}
                />

                <span className={`text-sm font-medium${sample.enabled ? '' : ' text-muted-foreground'}`}>Random</span>

                {/* % input — vertically aligned across rows by identical prefix */}
                <Input
                  aria-label={`Sampling percentage for corpus ${idx + 1}`}
                  type="number"
                  min={1}
                  max={100}
                  step={10}
                  value={displayPercent}
                  disabled={!sample.enabled || inputsDisabled}
                  className="h-8 w-14 flex-shrink-0 px-1.5 text-center text-sm"
                  onChange={(e) => onCorpusSampleChange(idx, { percent: e.target.value })}
                  onBlur={(e) => {
                    const raw = Number(e.target.value);
                    const clamped = Math.min(
                      100,
                      Math.max(1, isNaN(raw) ? 1 : Math.round(raw))
                    );
                    onCorpusSampleChange(idx, { percent: String(clamped) });
                  }}
                />

                <span className="text-sm font-medium">%</span>

                {nDocs > 0 && (
                  <span className="text-sm font-medium">
                    {`→ ~`}<span style={{ color }}>{effectiveDocs.toLocaleString()}</span>{` documents`}
                  </span>
                )}
              </div>
            );
          })}

          {showSamplingWarning && (
            <p className="rounded border border-amber-200 bg-amber-50 px-2 py-1 text-xs leading-tight text-amber-700">
              Sampled corpus may be too small for the target topic count.
            </p>
          )}
        </div>

        {/* ── Right column: Topic Modelling Options ── */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center gap-1.5">
            <Label className="text-sm font-medium">Topic Modelling Options</Label>
            <HelpIcon targetKey="analysis.topic-modeling.options" />
          </div>

          {/* Row 1: mode dropdown + value input */}
          <div className="flex items-center justify-between gap-2">
            <div className="flex min-w-0 flex-1 items-center gap-2">
              <Select
                value={topicSizeMode}
                onValueChange={(v) => onTopicSizeModeChange(v as 'min' | 'exact')}
                disabled={inputsDisabled}
              >
                <SelectTrigger className="h-8 flex-1 text-sm font-medium">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="exact" className="text-sm font-medium">Target Topic Number</SelectItem>
                  <SelectItem value="min" className="text-sm font-medium">Min Topic Size</SelectItem>
                </SelectContent>
              </Select>
              {topicSizeMode === 'exact' ? (
                <span
                  aria-label="Target Topic Number fits the model then merges topics to the chosen count"
                  title="Target Topic Number fits the model first and then merges topics to your chosen count, so it may run slower than Min Topic Size."
                  className="inline-flex h-8 w-8 flex-shrink-0 items-center justify-center text-muted-foreground"
                >
                  <CircleHelp className="h-4 w-4" />
                </span>
              ) : null}
            </div>
            <Input
              id="topic-size-value"
              aria-label="Topic size value"
              type="number"
              min={2}
              step={1}
              value={topicSizeValueDraft}
              disabled={inputsDisabled}
              title={
                topicSizeWarning === 'red'
                  ? 'Fewer than 3 documents per topic — results will likely be unusable'
                  : topicSizeWarning === 'orange'
                  ? 'Fewer than 10 documents per topic — topics may be noisy or unstable'
                  : undefined
              }
              className={`h-8 w-24 flex-shrink-0 px-2 text-right text-sm${
                topicSizeWarning === 'red'
                  ? ' text-red-500'
                  : topicSizeWarning === 'orange'
                  ? ' text-orange-500'
                  : !topicSizeUserSet
                  ? ' text-muted-foreground'
                  : ''
              }`}
              onChange={(e) => setTopicSizeValueDraft(e.target.value)}
              onBlur={handleTopicSizeValueBlur}
            />
          </div>

          {/* Row 2: random seed */}
          <div className="flex items-center justify-between gap-2">
            <Label htmlFor="random-seed" className="whitespace-nowrap pl-3 text-sm">
              Random Seed
            </Label>
            <Input
              id="random-seed"
              type="number"
              min={0}
              step={1}
              value={randomSeed}
              disabled={inputsDisabled}
              className={`h-8 w-24 text-right text-sm${!randomSeedUserSet ? ' text-muted-foreground' : ''}`}
              onChange={(e) => onRandomSeedChange(Math.max(0, Number(e.target.value) || 0))}
            />
          </div>

          {/* Row 3: words per topic */}
          <div className="flex items-center justify-between gap-2">
            <Label htmlFor="representative-words-count" className="whitespace-nowrap pl-3 text-sm">
              Words per topic
            </Label>
            <DisabledReasonTooltip
              reason={
                isLocked && representativeWordsCountServerMax
                  ? (representativeWordsCountLockedReason
                    ?? `Adjustable up to ${representativeWordsCountCap} after modelling. Clear Results to fit with a higher count.`)
                  : undefined
              }
            >
            <Input
              id="representative-words-count"
              type="number"
              min={3}
              max={representativeWordsCountCap}
              step={1}
              value={representativeWordsCountDraft}
              className={`h-8 w-24 text-right text-sm${!representativeWordsCountUserSet ? ' text-muted-foreground' : ''}`}
              onChange={(e) => setRepresentativeWordsCountDraft(e.target.value)}
              onBlur={handleRepresentativeWordsCountBlur}
            />
            </DisabledReasonTooltip>
          </div>
        </div>

      </div>
    </AnalysisCardLayout>
  );
}
